echo "
/* Mobile 3D Flip Effect */
@media (max-width: 768px) {
    .portfolio-image-link,
    .portfolio-card-wrapper {
        perspective: 1000px;
    }

    .portfolio-image {
        position: relative;
        transition: transform 0.8s;
        transform-style: preserve-3d;
        /* Need to manage overflow for border-radius with preserve-3d */
        overflow: visible !important;
    }

    .portfolio-image.is-flipped {
        transform: rotateY(180deg);
    }

    /* Standardize images for flip */
    .portfolio-image img {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        border-radius: 8px; /* Move border radius to images */
        backface-visibility: hidden;
        -webkit-backface-visibility: hidden;
        transition: none !important; /* Disable opacity transition on mobile */
    }

    /* Face 1: Default Image */
    .portfolio-image .thumb-default {
        z-index: 2;
        transform: rotateY(0deg);
        opacity: 1 !important;
    }

    /* Face 2: Hover (Back) Image */
    .portfolio-image .thumb-hover {
        transform: rotateY(180deg);
        z-index: 1;
        opacity: 1 !important; /* Always visible, just rotated */
    }
}
" >> c:\Users\joong\Desktop\Github\porrtfolio2026\css\style.css
